object Solution {
  def nums(nums: Array[Long]): Long = {
    // 1. Find the peak index
    var peakIndex = 0
    // Since the array is guaranteed to be bitonic (strictly increasing then strictly decreasing),
    // we can find the peak where nums[i] > nums[i+1] or at the end if it's strictly increasing.
    // For a bitonic array of length >= 3, the peak must exist such that the next element is smaller.
    while (peakIndex < nums.length - 1 && nums(peakIndex) < nums(peakIndex + 1)) {
      peakIndex += 1
